/**
 * Generic BFF response envelope returned by every WebApp.BFF endpoint.
 * Wraps the data payload with success status, message, and optional error detail.
 *
 * C# shape: ApiResponse<T> from Linm.CommonLib.Models
 */
export interface BffResponse<T> {
  success: boolean;
  message: string;
  data?: T;
  error?: { errorCode?: string; toastMessage?: string };
}

/**
 * Unwrap a BffResponse<T> — return the inner data on success,
 * or throw a localised error message on failure.
 */
export function unwrap<T>(response: BffResponse<T>): T {
  if (!response.success || response.data === undefined || response.data === null) {
    throw new Error(
      response.error?.toastMessage || response.message || 'Lỗi API'
    );
  }
  return response.data;
}
