import React from 'react';
import { Link } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { Button, Input, TableCard } from '../../ui';
import {
  jobsService,
  type DataSyncSetConfigItem,
  type ExternalConnectorOptions,
  type UpdateDataSyncSetConfigRequest,
} from '../../services/jobs';
import { useAppToast } from '../../hooks/useAppToast';

const defaultOptions = (): ExternalConnectorOptions => ({
  searchPath: '',
  detailPathTemplate: null,
  documentKeyField: 'soHoaDon',
  detailKeyParam: 'billId',
  pageSize: 100,
  parallelJobs: 4,
  timeoutSeconds: 60,
  maxRetries: 3,
  dateOffsetDays: 0,
  syncLookbackDays: 1,
  apiKeyHeader: 'x-api-key',
  fetchDetailBeforeImport: true,
});

const parseOptions = (json?: string | null): ExternalConnectorOptions => {
  if (!json) return defaultOptions();
  try {
    return { ...defaultOptions(), ...JSON.parse(json) };
  } catch {
    return defaultOptions();
  }
};

const DataSyncSetConfigPage: React.FC = () => {
  useNavTitle('Cấu hình sync REVA FM');
  const toast = useAppToast();
  const [rows, setRows] = React.useState<DataSyncSetConfigItem[]>([]);
  const [loading, setLoading] = React.useState(true);
  const [editing, setEditing] = React.useState<DataSyncSetConfigItem | null>(null);
  const [form, setForm] = React.useState<UpdateDataSyncSetConfigRequest>({ isEnabled: true });
  const [options, setOptions] = React.useState<ExternalConnectorOptions>(defaultOptions());
  const [fromDate, setFromDate] = React.useState('');
  const [toDate, setToDate] = React.useState('');
  const [saving, setSaving] = React.useState(false);
  const [running, setRunning] = React.useState<string | null>(null);

  const load = React.useCallback(() => {
    setLoading(true);
    jobsService
      .getExternalSetConfigs()
      .then(setRows)
      .catch((e: Error) => toast.error(e.message))
      .finally(() => setLoading(false));
  }, [toast]);

  React.useEffect(() => load(), [load]);

  const startEdit = (row: DataSyncSetConfigItem) => {
    setEditing(row);
    setForm({
      isEnabled: row.isEnabled,
      externalBaseUrl: row.externalBaseUrl ?? '',
      endpointRouteTemplate: row.endpointRouteTemplate ?? '',
      chunkSize: row.chunkSize,
    });
    setOptions(parseOptions(row.optionsJson));
  };

  const save = async () => {
    if (!editing) return;
    setSaving(true);
    try {
      await jobsService.updateExternalSetConfig(editing.configKey, {
        ...form,
        optionsJson: JSON.stringify(options, null, 2),
      });
      toast.success('Đã lưu cấu hình connector');
      setEditing(null);
      load();
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi lưu');
    } finally {
      setSaving(false);
    }
  };

  const runSync = async (configKey: string) => {
    setRunning(configKey);
    try {
      const res = await jobsService.triggerExternalSync(configKey, {
        fromDate: fromDate || null,
        toDate: toDate || null,
      });
      toast.success(`Đã enqueue sync — runId ${res.runId.slice(0, 8)}…`);
    } catch (e: unknown) {
      toast.error(e instanceof Error ? e.message : 'Lỗi chạy job');
    } finally {
      setRunning(null);
    }
  };

  return (
    <div data-testid="data-sync-set-config-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/inbound">Inbound dashboard</Link>
      </p>
      <p style={{ color: '#555', marginBottom: 16 }}>
        Cấu hình connector REVA FM (search → detail → import). Job init gọi search <code>pageSize=1</code>{' '}
        lấy <code>totalItems</code>, chia trang, chạy song song theo <strong>parallelJobs</strong>, mỗi
        document tracking qua <code>data_sync_checkpoints</code>.
      </p>

      <div style={{ display: 'flex', gap: 12, marginBottom: 16, flexWrap: 'wrap' }}>
        <Input label="fromDate (tùy chọn)" value={fromDate} onChange={(e) => setFromDate(e.target.value)} placeholder="yyyy-MM-dd" />
        <Input label="toDate (tùy chọn)" value={toDate} onChange={(e) => setToDate(e.target.value)} placeholder="yyyy-MM-dd" />
      </div>

      <TableCard>
        {loading ? (
          <p>Đang tải…</p>
        ) : (
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th align="left">Connector</th>
                <th align="left">Base URL</th>
                <th align="left">Enabled</th>
                <th align="left">Page / Parallel</th>
                <th />
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => {
                const opt = parseOptions(r.optionsJson);
                return (
                  <tr key={r.configKey}>
                    <td>
                      <strong>{r.configKey}</strong>
                      <br />
                      <small>{opt.searchPath}</small>
                    </td>
                    <td style={{ fontSize: 12 }}>{r.externalBaseUrl ?? '—'}</td>
                    <td>{r.isEnabled ? 'Có' : 'Không'}</td>
                    <td>
                      {opt.pageSize} / {opt.parallelJobs}
                    </td>
                    <td style={{ whiteSpace: 'nowrap' }}>
                      <Button type="button" variant="secondary" onClick={() => startEdit(r)} style={{ marginRight: 8 }}>
                        Sửa
                      </Button>
                      <Button
                        type="button"
                        onClick={() => runSync(r.configKey)}
                        disabled={!r.isEnabled || running === r.configKey}
                      >
                        {running === r.configKey ? 'Đang gửi…' : 'Chạy sync'}
                      </Button>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </TableCard>

      {editing ? (
        <div style={{ marginTop: 24, maxWidth: 560 }}>
          <h3>Sửa: {editing.configKey}</h3>
          <label style={{ display: 'flex', gap: 8, alignItems: 'center', marginBottom: 8 }}>
            <input
              type="checkbox"
              checked={form.isEnabled}
              onChange={(e) => setForm((f) => ({ ...f, isEnabled: e.target.checked }))}
            />
            Enabled
          </label>
          <Input
            label="External base URL"
            value={form.externalBaseUrl ?? ''}
            onChange={(e) => setForm((f) => ({ ...f, externalBaseUrl: e.target.value }))}
          />
          <Input
            label="ERP import route (endpointRouteTemplate)"
            value={form.endpointRouteTemplate ?? ''}
            onChange={(e) => setForm((f) => ({ ...f, endpointRouteTemplate: e.target.value }))}
          />
          <Input
            label="Search path"
            value={options.searchPath}
            onChange={(e) => setOptions((o) => ({ ...o, searchPath: e.target.value }))}
          />
          <Input
            label="Detail path template ({id})"
            value={options.detailPathTemplate ?? ''}
            onChange={(e) => setOptions((o) => ({ ...o, detailPathTemplate: e.target.value || null }))}
          />
          <Input
            label="Document key field"
            value={options.documentKeyField}
            onChange={(e) => setOptions((o) => ({ ...o, documentKeyField: e.target.value }))}
          />
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8 }}>
            <Input
              label="Page size"
              type="number"
              value={String(options.pageSize)}
              onChange={(e) => setOptions((o) => ({ ...o, pageSize: Number(e.target.value) || 1 }))}
            />
            <Input
              label="Parallel jobs"
              type="number"
              value={String(options.parallelJobs)}
              onChange={(e) => setOptions((o) => ({ ...o, parallelJobs: Number(e.target.value) || 1 }))}
            />
            <Input
              label="Timeout (s)"
              type="number"
              value={String(options.timeoutSeconds)}
              onChange={(e) => setOptions((o) => ({ ...o, timeoutSeconds: Number(e.target.value) || 60 }))}
            />
            <Input
              label="Max retries"
              type="number"
              value={String(options.maxRetries)}
              onChange={(e) => setOptions((o) => ({ ...o, maxRetries: Number(e.target.value) || 3 }))}
            />
            <Input
              label="Date offset (ngày)"
              type="number"
              value={String(options.dateOffsetDays)}
              onChange={(e) => setOptions((o) => ({ ...o, dateOffsetDays: Number(e.target.value) || 0 }))}
            />
            <Input
              label="Sync lookback (ngày)"
              type="number"
              value={String(options.syncLookbackDays)}
              onChange={(e) => setOptions((o) => ({ ...o, syncLookbackDays: Number(e.target.value) || 1 }))}
            />
          </div>
          <Input
            label="API key config (appsettings)"
            value={options.apiKeyConfigKey ?? ''}
            onChange={(e) => setOptions((o) => ({ ...o, apiKeyConfigKey: e.target.value || null }))}
            placeholder="RevaFm:ApiKey"
          />
          <div style={{ display: 'flex', gap: 8, marginTop: 12 }}>
            <Button type="button" onClick={save} disabled={saving}>
              Lưu
            </Button>
            <Button type="button" variant="secondary" onClick={() => setEditing(null)}>
              Hủy
            </Button>
          </div>
        </div>
      ) : null}
    </div>
  );
};

export default DataSyncSetConfigPage;
